import React, { useCallback, useMemo, useRef, useState } from 'react';
import {
  Button,
  Input,
  SearchTextInput,
  Select,
  Slideout,
  Checkbox,
  TextArea,
  MoneyInput,
  NumberInput,
  SearchInput,
  dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { createAccountSearchConfig, createMaterialGroupSearchConfig, formatAccountDisplay } from '../../../components/search';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { getSharedCatalogEditBlockedMessage, catalogRowEditHintDismissStorageKey } from '../../../utils/sharedCatalogEditBlockedMessage';
import {
  CATALOG_LIST_ROW_MENU_HINT_DESKTOP,
  CATALOG_LIST_ROW_MENU_HINT_TOUCH,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import {
  CatalogFormFooter,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListGridFromSchema,
  CatalogListMasterLinPageLayout,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogCodeReplaceProvider,
  CatalogListHeaderFilters,
  CatalogRowActionMenu,
  type CatalogRowMenuAction,
  type CatalogListToolbarBridge,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { masterService } from '../../../services/master/masterService';
import type { MaterialDto, MaterialGroupDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-vat-tu';
const CATALOG_KIND = 'materials';

const emptyForm = (): Partial<MaterialDto> => ({
  isActive: true,
  standardCost: 0,
  unitCode: '',
});

type FormErrors = Partial<
  Record<'code' | 'name' | 'categoryCode' | 'unitCode' | 'maxStockLevel', string>
>;

type MaterialGridRow = MaterialDto;

const VatTuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: MaterialGridRow } | null>(null);
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<MaterialDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [materialGroups, setMaterialGroups] = useState<MaterialGroupDto[]>([]);
  const materialGroupSearchConfig = useMemo(
    () => createMaterialGroupSearchConfig(materialGroups),
    [materialGroups],
  );
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<MaterialDto | null>(null);
  const [form, setForm] = useState<Partial<MaterialDto>>(emptyForm());
  const [accountName, setAccountName] = useState('');
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const initFormName = modalOpen && editing ? 'edit-material' : 'create-material';
  const { unitOptions } = useVoucherInitData(initFormName);

  const selectedGroup = useMemo(
    () =>
      materialGroups.find(
        g => g.id === form.materialGroupId || g.code === form.categoryCode,
      ),
    [materialGroups, form.materialGroupId, form.categoryCode],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: r => !isSharedCatalogReadOnly(r),
  });

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService
        .getMaterialGroups({ page: 1, pageSize: 500 })
        .then(data => {
          if (!cancelled) setMaterialGroups(data.items);
        })
        .catch(() => { /* non-blocking */ });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [reloadKey]);

  React.useEffect(() => {
    if (!modalOpen || !form.accountCode?.trim()) {
      if (!form.accountCode) setAccountName('');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccounts({ isActive: true, isDetail: true, page: 1, pageSize: 500 }).then(res => {
        if (!cancelled) {
          const a = res.items.find(x => x.code === form.accountCode);
          setAccountName(a?.name ?? '');
        }
      });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [modalOpen, form.accountCode]);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getMaterials({ search: search || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải danh mục vật tư', type: 'error' });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã vật tư';
    if (!form.name?.trim()) next.name = 'Nhập tên vật tư';
    if (!form.categoryCode?.trim() && !form.materialGroupId) next.categoryCode = 'Chọn nhóm vật tư';
    if (!form.unitCode?.trim()) next.unitCode = 'Chọn đơn vị tính';
    const min = form.minStockLevel;
    const max = form.maxStockLevel;
    if (min != null && max != null && max < min) {
      next.maxStockLevel = 'Tồn tối đa phải ≥ tồn tối thiểu';
    }
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const onGroupChange = (g: MaterialGroupDto) => {
    markDirty();
    clearFieldError('categoryCode');
    setForm(f => ({
      ...f,
      materialGroupId: g.id,
      categoryCode: normalizeCode(g.code),
    }));
  };

  const resolveMaterialForm = (row: MaterialDto): Partial<MaterialDto> => {
    if (row.categoryCode || !row.materialGroupId) return { ...row };
    const g = materialGroups.find(x => x.id === row.materialGroupId);
    return g ? { ...row, categoryCode: g.code } : { ...row };
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm(emptyForm());
    setAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: MaterialGridRow) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm(resolveMaterialForm(row));
    setAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean, materialGroups]);

  const openEdit = useCallback((row: MaterialGridRow) => {
    if (!canWrite || isSharedCatalogReadOnly(row)) {
      openView(row);
      return;
    }
    setViewOnlyShared(false);
    setEditing(row);
    setForm(resolveMaterialForm(row));
    setAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [canWrite, markClean, materialGroups, openView]);

  const handleSave = async () => {
    const payload: Partial<MaterialDto> = { ...form };
    if (!payload.materialGroupId && payload.categoryCode) {
      const g = materialGroups.find(x => x.code === payload.categoryCode);
      if (g) payload.materialGroupId = g.id;
    }

    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      document
        .querySelector<HTMLElement>(`[data-testid^="${TEST_ID}-field-"]`)
        ?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateMaterial(editing.id, payload);
      else await masterService.createMaterial(payload);
      markClean();
      dispatchAppToast(dispatch, {
          message: editing ? 'Cập nhật vật tư thành công' : 'Tạo vật tư thành công',
          type: 'success',
        }
      );
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateMaterial(id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} vật tư`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteMaterial(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} vật tư`, type: 'success' });
    }
    refresh();
  };

  const handleExport = async () => {
    setExporting(true);
    try {
      await masterService.exportMaterialsCsv({ search: search || undefined });
      dispatchAppToast(dispatch, { message: 'Xuất file thành công', type: 'success' });
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Xuất file thất bại', type: 'error' });
    } finally {
      setExporting(false);
    }
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };
  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const rowMenuHintMessage = viewMobile
    ? CATALOG_LIST_ROW_MENU_HINT_TOUCH
    : CATALOG_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: MaterialGridRow; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'renameCode':
          toolbarBridgeRef.current?.openRename();
          break;
        case 'delete': {
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        }
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuReadOnly = rowMenuRow ? isSharedCatalogReadOnly(rowMenuRow) : false;
  const rowMenuShowEdit = !!rowMenuRow && canWrite && !rowMenuReadOnly;
  const rowMenuShowView = !!rowMenuRow && (!canWrite || rowMenuReadOnly);

  const listBody = items.length === 0 ? (
    <div className={styles.empty}>
      <i className="fas fa-inbox" />
      <p>{search.trim() ? 'Không tìm thấy vật tư phù hợp' : 'Không có dữ liệu'}</p>
    </div>
  ) : listColumns.length > 0 ? (
    <CatalogListGridFromSchema
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      columns={listColumns}
      schema={schema}
      selection={selection}
      getRowId={r => r.id}
      isRowSelectable={r => !isSharedCatalogReadOnly(r)}
      getRowEditBlockedMessage={getSharedCatalogEditBlockedMessage}
      rowEditHintDismissStorageKey={catalogRowEditHintDismissStorageKey(TEST_ID)}
      onRowOpenActionMenu={handleRowOpenActionMenu}
      rowMenuHintMessage={rowMenuHintMessage}
      rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
      enableRowMenuLongPress={viewMobile}
    />
  ) : null;

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={toolbarBridgeRef}
        toolbarExtraLeftActions={(
          <Button
            variant="secondary"
            size="sm"
            onClick={handleExport}
            disabled={exporting}
            data-testid={`${TEST_ID}-export-btn`}
          >
            <i className="fas fa-file-excel" /> {exporting ? 'Đang xuất...' : 'Xuất Excel'}
          </Button>
        )}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{ title: 'Danh mục vật tư', titleIconClass: 'fas fa-boxes' }}
        listTitle="Danh sách vật tư"
        filtersTestId="dm-vat-tu-filters"
        filterMaxWidthPx={1000}
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
            <LinListFilterField testId={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </LinListFilterField>
          </CatalogListHeaderFilters>
        )}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showEdit={rowMenuShowEdit}
              showView={rowMenuShowView}
              showHistory={!!rowMenuRow}
              showRename={rowMenuShowEdit}
              showDelete={rowMenuShowEdit}
            />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {listBody}
      </CatalogListMasterLinPageLayout>

      <Slideout
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem vật tư dùng chung' : editing ? 'Sửa vật tư' : 'Thêm vật tư'}
        width="600px"
        data-testid={`${TEST_ID}-slideout`}
        customFooter={(
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            variant="slideout"
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            historySlot={
              <>
                <CatalogFormCodeReplaceSlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                  reloadKey={reloadKey}
                />
                <CatalogFormHistorySlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                />
              </>
            }
            saveDisabled={viewOnlyShared}
            activeDisabled={viewOnlyShared}
          />
        )}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã vật tư *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên vật tư *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-groupCode`}>
              <label className={styles.label}>Nhóm vật tư *</label>
              <SearchInput
                config={materialGroupSearchConfig}
                value={form.materialGroupId ?? selectedGroup?.id ?? ''}
                primaryDisplay={form.categoryCode ?? selectedGroup?.code ?? ''}
                secondaryDisplay={selectedGroup?.name ?? ''}
                disabled={viewOnlyShared}
                error={errors.categoryCode}
                onChange={onGroupChange}
                onClear={() => {
                  markDirty();
                  clearFieldError('categoryCode');
                  setForm(f => ({
                    ...f,
                    materialGroupId: undefined,
                    categoryCode: undefined,
                  }));
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder="Mã hoặc tên nhóm..."
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-unit`}>
              <label className={styles.label}>Đơn vị tính *</label>
              <Select
                value={form.unitCode ?? ''}
                required
                placeholder="— Chọn ĐVT —"
                disabled={viewOnlyShared}
                error={errors.unitCode}
                className={selectPlaceholderClass(form.unitCode)}
                onChange={e => {
                  markDirty();
                  clearFieldError('unitCode');
                  setForm(f => ({ ...f, unitCode: normalizeCode(e.target.value) }));
                }}
                options={unitOptions}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-accountCode`}>
              <label className={styles.label}>TK kho (hàng tồn)</label>
              <SearchInput
                config={accountSearchConfig}
                value={form.accountCode ?? ''}
                disabled={viewOnlyShared}
                primaryDisplay={formatAccountDisplay(form.accountCode ?? '', accountName)}
                onChange={a => {
                  markDirty();
                  setForm(f => ({ ...f, accountCode: normalizeCode(a.code) }));
                  setAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, accountCode: undefined }));
                  setAccountName('');
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder="Mã hoặc tên TK..."
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-standardCost`}>
              <label className={styles.label}>Giá tiêu chuẩn (VNĐ)</label>
              <MoneyInput
                value={form.standardCost ?? 0}
                disabled={viewOnlyShared}
                onChange={v => {
                  markDirty();
                  setForm(f => ({ ...f, standardCost: v }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-minStockLevel`}>
              <label className={styles.label}>Tồn kho tối thiểu</label>
              <NumberInput
                value={form.minStockLevel ?? 0}
                disabled={viewOnlyShared}
                onChange={v => {
                  markDirty();
                  clearFieldError('maxStockLevel');
                  setForm(f => ({ ...f, minStockLevel: v > 0 ? v : undefined }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-maxStockLevel`}>
              <label className={styles.label}>Tồn kho tối đa</label>
              <NumberInput
                value={form.maxStockLevel ?? 0}
                disabled={viewOnlyShared}
                error={errors.maxStockLevel}
                onChange={v => {
                  markDirty();
                  clearFieldError('maxStockLevel');
                  setForm(f => ({ ...f, maxStockLevel: v > 0 ? v : undefined }));
                }}
              />
            </div>
            <div
              className={styles.field}
              style={{ gridColumn: '1 / -1' }}
              data-testid={`${TEST_ID}-field-note`}
            >
              <label className={styles.label}>Ghi chú</label>
              <TextArea
                rows={2}
                disabled={viewOnlyShared}
                value={form.description ?? ''}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, description: e.target.value }));
                }}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              categoryCode: form.categoryCode,
              unitCode: form.unitCode,
              standardCost: form.standardCost,
              accountCode: form.accountCode,
              description: form.description,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
        </div>
      </Slideout>
    </CatalogCodeReplaceProvider>
  );
};

export default VatTuPage;
